#include<bits/stdc++.h>
using namespace std;
int n,b,cnt,rt[1010],id[1010];
stack<int> s;
vector<int> mp[1010];
void dfs(int x,int fa=-1)
{
    int tmp=s.size();
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            if((int)(s.size())-tmp>=b)
            {
                rt[++cnt]=x;
                while((int)(s.size())>tmp)
                {
                    id[s.top()]=cnt;
                    s.pop();
                }
            }
        }
    }
    s.push(x);
}
int main()
{
    scanf("%d%d",&n,&b);
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs(1);
    if(cnt==0)
    {
        rt[++cnt]=1;
    }
    while(!s.empty())
    {
        id[s.top()]=cnt;
        s.pop();
    }
    printf("%d\n",cnt);
    for(int i=1;i<=n;i++)
    {
        printf("%d ",id[i]);
    }
    printf("\n");
    for(int i=1;i<=cnt;i++)
    {
        printf("%d ",rt[i]);
    }
    return 0;
}
